form:Form.form:Scripts:
		var xmlListaWF;
var listaParametros = new Array(); //Lista de todos los parametros que utilizan los wf dentro del grupo seleccionado. De aca se van a recuperar y validar
						  //los datos que necesitan cada uno de los wf para comerzarse a ejectuar.
var arrDataParamWF = new Array(); //Contiene para cada WF sus parametros. Los valores para estos parametros van a ser obtenidos del array listaParametros

var wfSelected; //Guardo el codigo del workflow seleccionado del super combo una vez que se hace click en iniciar.                                       
var wfXML; //Guardo el xml del wf seleccionado para iniciarse a partir del codigo del "wfSelected"

var iniciaWF;
var idWFStarted;

var validarExtras = 0; //Var bool que indica a la hora de querer iniciar en wf si hay validaciones extras ademas de los parametros del propio wf que se desea iniciar.
var msgError = new Array(); //Contiene para cada wf un mensaje de error que se tiene que mostrar en caso de no cumplir con los requisitos. El mensaje se setea desde el reporte.
								  //En el reporte del wf de domicilios hay un ejemplo.

function Form_OnLoad() {
xmlListaWF = Ctrl("main").GetLastDocXML("listaWF");
LoadReporte();
LoadParamWF();
LoadDataParamWF();	
Ctrl("btnIniciar").SetEnabled(false);
}


function LoadReporte(){
		var reporte = Ctrl("reporte").GetCValue();
		var workflow = Ctrl("workflow").GetCValue();                                                                                                                                                 

		Ctrl("controlReporte").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&amp;file="+reporte+"&amp;oi_usuario_sistema="+GetProxy().Etty()+"&amp;crc="+Ctrl("crc").GetXValue());
		//Ctrl("controlReporte").SetURL("../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&amp;file=NucleusWF.Base.Ejecucion.BaseInicioWF.rpt&amp;oi_usuario_sistema="+Ctrl("oi_usuario_sistema").GetCValue()+"&amp;reporte="+Ctrl("nombre_reporte").GetCValue());
}


function LoadParamWF(){
//Guardo todos los parametros que hay en los WF para cuando iniciar alguno obtener los datos.
for(var option = xmlListaWF.FirstChild(); option != null; option = option.Next()){
	//Incluyo los parametros de cada uno. Si se repite el mismo parametro en mas de un WF se pisan y queda uno solo. 
	for(var param = option.FirstChild().FirstChild(); param != null; param = param.Next()){		
		listaParametros[param.GetAttr("c_name")] = undefined;
	}              
}
}


function LoadDataParamWF(){
//Guardo para cada workflow los parámetros que requieren para iniciarse.
for(var option = xmlListaWF.FirstChild(); option != null; option = option.Next()){
	arrDataParamWF[option.GetAttr("value")] = new Array();
	//Inicializo los mensajes de errores para cada wf en vacio.
	msgError[option.GetAttr("value")] = "";
	for(var param = option.FirstChild().FirstChild(); param != null; param = param.Next()){
		arrDataParamWF[option.GetAttr("value")][param.GetAttr("c_name")] = undefined;
	}
}
}


function StartWF(){
	idWFStarted = undefined;
	wfSelected = Ctrl("cmbWorkFlows").GetXValue();
	//alert("wfSelected:" + wfSelected);
	if(msgError[wfSelected] != ""){
		alert(msgError[wfSelected]);
		return false;	
	}

var xmlData = new NomadXML("DATA");

iniciaWF = true;
if(wfSelected == ""){
	alert("Debe seleccionar una acción");
	iniciaWF = false;
}else{
	//Busca el workflow para saber los atributos que necesita tener seteados
	wfXML = xmlListaWF.FindElement2("option","value",wfSelected);
	if(wfXML == null){
		alert("No se encontró el wf para iniciarse.");
		iniciaWF = false;
	}else{
		//Seteo el id del wf a iniciar
		idWFStarted = wfXML.GetAttr("id_wf");

	    //Si no tiene parametros inicia directamente, sino evalua que esten todos seteados
	    if(wfXML.FirstChild().GetChilds().length == 0){
	    	iniciaWF = true;

	  	}else{
	  		for(param = wfXML.FirstChild().FirstChild(); param != null; param = param.Next()){
	  			if(listaParametros[param.GetAttr("c_name")] == undefined || listaParametros[param.GetAttr("c_name")] == ""){
	  				alert(param.GetAttr("desc") + " es necesario que tenga un valor para poder iniciar el workflow");
	  				iniciaWF = false;
	  				break;
	  			}

	  			arrDataParamWF[wfSelected][param.GetAttr("c_name")] =  GetParam(param.GetAttr("c_name"));
				xmlData.SetAttr(param.GetAttr("c_name"),GetParam(param.GetAttr("c_name")));
	  		}
	  	}
	}	
}

if(iniciaWF == true){
	//console.log("id wf iniciado:" + idWFStarted);
	xmlData.SetAttr("oi_wf",idWFStarted);
	xmlData.SetAttr("DEBUG","0");

	getFormInMain("NucleusWF.Base.Ejecucion.Formularios.ShowForm.flow", "CREATE", xmlData.ToString(), false);
}else{
	//alert("No se puede iniciar el workflow");
}

return true;
}

function GetParam(name_param){
return listaParametros[name_param];
}

function SetParam(name_param, value){
listaParametros[name_param] = value;
//console.log(name_param);
//console.log(value);
}

function EnableBtnSend(obj){
var value = obj.GetXValue();

if(value != undefined && value != null && value != ""){
	Ctrl("btnIniciar").SetEnabled(true);
}else{
	Ctrl("btnIniciar").SetEnabled(false);
}
}

//Setea los mensajes de errores para cuando se quiere iniciar un wf que no se puede. Los mensajes se setean desde el reporte.
function SetMsgError(idWF,msg){
	msgError[idWF] = msg;
}
